// n8n Code node
// Input: Gemini output
// Output: ONE item: { items: [ { name, confidence } ] }

const data = $input.first().json;
const text =
  data?.content?.parts?.map(p => p?.text).filter(Boolean).join('\n') ||
  data?.candidates?.[0]?.content?.parts?.map(p => p?.text).filter(Boolean).join('\n') ||
  data?.text ||
  '';

const items = text
  .split(/\r?\n/)
  .map(l => l.trim())
  .filter(Boolean)
  .map(l => l.replace(/^(\*|-|•|\d+[.)])\s+/, '').trim())
  .filter(Boolean)
  .filter(l => l.length > 1);

const seen = new Set();
const uniqueItems = items
  .filter(x => x.toLowerCase() !== 'unsure')
  .filter(x => {
    const key = x.toLowerCase();
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });

return [{
  json: {
    items: uniqueItems.map(name => ({ name, confidence: 0.7 }))
  }
}];

// --------------- 1) Accept BOTH direct items and text/JSON model output ---------------
let items = [];

if (Array.isArray($json?.items)) {
  items = $json.items;
}

if (!items.length) {
  const responseText =
    $json?.text ||
    $json?.candidates?.[0]?.content?.parts?.[0]?.text ||
    $json?.content?.parts?.map(p => p?.text).filter(Boolean).join('\n') ||
    JSON.stringify($json || { items: [] });

  try {
    const cleaned = String(responseText).replace(/```json|```/g, '').trim();
    const parsed = JSON.parse(cleaned);
    items = Array.isArray(parsed.items) ? parsed.items : [];
  } catch (e) {
    items = [];
  }
}

// --------------- 2) Process items (names only) ---------------
const seen = new Set();

const processedItems = items
  .map(item => {
    const name = String(item?.name ?? item?.label ?? '')
      .toLowerCase()
      .trim();
    return { label: name, detected: name };
  })
  .filter(x => x.label && x.label.length > 1 && x.label !== 'unsure')
  .filter(x => {
    if (seen.has(x.label)) return false;
    seen.add(x.label);
    return true;
  });

// --------------- 3) Chat ID ---------------
function getChatId(obj) {
  return (
    obj?.message?.chat?.id ??
    obj?.chat?.id ??
    obj?.callback_query?.message?.chat?.id ??
    obj?.message?.from?.id ??
    obj?.chat_id ??
    obj?.chatId ??
    null
  );
}

const chat_id =
  getChatId($input.first()?.json ?? {}) ??
  getChatId($('Telegram Trigger3').first().json ?? {}) ??
  getChatId($json) ??
  null;

return [{
  json: {
    items: processedItems,
    total: processedItems.length,
    chat_id
  }
}];

const items = $json.items;

const chatId =
  $json.chat_id ??
  $('Telegram Trigger3').first().json.message.chat.id ??
  $('Telegram Trigger3').first().json.message.from.id;

if (!items || items.length === 0) {
  return [
    {
      json: {
        message: "😕 I couldn't detect any ingredients in this image. Please try again with a clearer photo!",
        ingredients_for_recipe: '',
        detected_names: [],
        detected_count: 0,
        chat_id: chatId,
        items: []
      }
    }
  ];
}

let msg = `🥦 *Detected ${items.length} ingredient(s):*\n\n`;

items.forEach((item) => {
  msg += `• *${item.label}*\n`;
});

msg += `\n🍳 *Finding recipes for you now...*`;

const ingredientNames = items.map(i => i.label);

return [
  {
    json: {
      message: msg,
      ingredients_for_recipe: ingredientNames.join(','),
      detected_names: ingredientNames,
      detected_count: ingredientNames.length,
      chat_id: chatId,
      items: items
    }
  }
];

const allItems = $input.all();
let recipes = [];

for (const item of allItems) {
  const j = item.json;

  if (Array.isArray(j)) {
    recipes = j.filter(r => r && (r.id || r.title));
    if (recipes.length) break;
  }

  if (j?.body && Array.isArray(j.body)) {
    recipes = j.body.filter(r => r && (r.id || r.title));
    if (recipes.length) break;
  }

  if (Array.isArray(j?.recipes)) {
    recipes = j.recipes.filter(r => r && (r.id || r.title));
    if (recipes.length) break;
  }

  if (Array.isArray(j?.results)) {
    recipes = j.results.filter(r => r && (r.id || r.title));
    if (recipes.length) break;
  }
}

if (!recipes.length) {
  const maybeRecipes = allItems
    .map(i => i.json)
    .filter(r => r && !Array.isArray(r) && (r.id || r.title));
  if (maybeRecipes.length) recipes = maybeRecipes;
}

let chatId = null;
let detectedItems = [];
let detectedNames = [];

try {
  const build = $('Build Ingredient Summary3').first().json || {};
  chatId = build.chat_id ?? null;
  detectedItems = Array.isArray(build.items) ? build.items : [];
  detectedNames = Array.isArray(build.detected_names)
    ? build.detected_names.map(x => String(x).toLowerCase().trim()).filter(Boolean)
    : [];
} catch (e) {}

const totalDetected = detectedNames.length;

function normalize(str) {
  return String(str || '')
    .toLowerCase()
    .trim();
}

function recipeUsesAllDetected(recipe, detectedNames) {
  const used = Array.isArray(recipe.usedIngredients) ? recipe.usedIngredients : [];
  const usedNames = used.map(i => normalize(i?.name));

  return detectedNames.every(detected =>
    usedNames.some(usedName =>
      usedName === detected ||
      usedName.includes(detected) ||
      detected.includes(usedName)
    )
  );
}

const strictRecipes = recipes.filter(recipe => recipeUsesAllDetected(recipe, detectedNames));

// fallback: if strict match fails, sort by most used ingredients
const rankedRecipes = [...recipes].sort((a, b) => {
  const aUsed = Array.isArray(a.usedIngredients) ? a.usedIngredients.length : 0;
  const bUsed = Array.isArray(b.usedIngredients) ? b.usedIngredients.length : 0;
  return bUsed - aUsed;
});

const finalRecipes = strictRecipes.length ? strictRecipes : rankedRecipes;

return [{
  json: {
    chat_id: chatId,
    recipes: finalRecipes,
    recipe_count: finalRecipes.length,
    total_detected: totalDetected,
    detected_names: detectedNames,
    used_all_detected: strictRecipes.length > 0
  }
}];

const stepItems = $input.all();
const recipeSource = $('Prepare Recipe Loop3').first().json || {};
const recipes = Array.isArray(recipeSource.recipes) ? recipeSource.recipes : [];
const detectedNames = Array.isArray(recipeSource.detected_names)
  ? recipeSource.detected_names.map(x => String(x).toLowerCase().trim())
  : [];

const chatId = $('Send Ingredient List3').first().json.result.chat.id;

// ----------------------
// Helpers
// ----------------------
function cleanText(value) {
  if (value == null) return "";
  return String(value).replace(/\s+/g, " ").trim();
}

function normalize(value) {
  return cleanText(value).toLowerCase();
}

function titleCase(str) {
  return cleanText(str)
    .split(" ")
    .map(word => word ? word.charAt(0).toUpperCase() + word.slice(1) : "")
    .join(" ");
}

function extractInstructionBlocks(json) {
  if (Array.isArray(json) && json.length > 0) return json;
  if (Array.isArray(json?.body) && json.body.length > 0) return json.body;
  return [];
}

function extractSteps(json) {
  const blocks = extractInstructionBlocks(json);
  if (blocks.length && Array.isArray(blocks[0].steps)) return blocks[0].steps;
  if (Array.isArray(json?.steps)) return json.steps;
  return [];
}

function getUsedIngredients(recipe) {
  if (!Array.isArray(recipe.usedIngredients)) return [];
  return recipe.usedIngredients
    .map(i => cleanText(i.name))
    .filter(Boolean);
}

function getMissedIngredients(recipe) {
  if (!Array.isArray(recipe.missedIngredients)) return [];
  return recipe.missedIngredients
    .map(i => cleanText(i.name))
    .filter(Boolean);
}

// ----------------------
// Build one Telegram message per recipe
// ----------------------
const output = [];

for (let i = 0; i < recipes.length; i++) {
  const recipe = recipes[i] || {};
  const stepJson = stepItems[i]?.json || {};
  const steps = extractSteps(stepJson);

  const title = cleanText(recipe.title) || `Recipe ${i + 1}`;
  const recipeId = recipe.id;
  const slug = title
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "");
  const recipeUrl = recipeId
    ? `https://spoonacular.com/recipes/${slug}-${recipeId}`
    : "";

  let usedIngredients = getUsedIngredients(recipe);
  const missedIngredients = getMissedIngredients(recipe);

  if (!usedIngredients.length && detectedNames.length) {
    usedIngredients = detectedNames.map(titleCase);
  }

  let msg = `🍽️ *Recipe ${i + 1}: ${title}*\n\n`;

  msg += `✅ *From your ingredients:*\n`;
  if (usedIngredients.length) {
    usedIngredients.forEach(item => {
      msg += `• ${item}\n`;
    });
  } else {
    msg += `• None clearly matched\n`;
  }

  msg += `\n🛒 *You might need:*\n`;
  if (missedIngredients.length) {
    missedIngredients.forEach(item => {
      msg += `• ${item}\n`;
    });
  } else {
    msg += `• Nothing else needed\n`;
  }

  msg += `\n📋 *Steps:*\n`;
  if (steps.length) {
    steps.forEach((step, idx) => {
      const instruction = cleanText(step.step);
      msg += `${idx + 1}. ${instruction}\n\n`;
    });
  } else {
    msg += `1. Sorry, I couldn't retrieve the steps for this recipe.\n\n`;
  }

  if (recipeUrl) {
    msg += `🔗 *View Full Recipe:* ${recipeUrl}`;
  }

  output.push({
    json: {
      chat_id: chatId,
      message: msg.trim()
    }
  });
}

return output;
